This problem has to do with dynamic components being asynchronously loaded and therefore properties on the default import do not exist yet. An alternative approach would be to separate this component into its own file and dynamically load it within the page (this will also avoid having to type cast a 3rd party dynamic component and its properties):

**page/index.js**
```jsx
const Table = dynamic(() => import("../components/Table"), {
  ssr: false,
});

<Table data={data} dataColumns={dataColumns} id="users" />
```

**components/Table.js** (this allows the table to be reusable; otherwise, you can hard-code the table's layout if you're only dealing with one data structure):
```jsx
import get from "lodash.get";
import Table from "rsuite/Table";
import "rsuite-table/dist/css/rsuite-table.min.css";

export default function CustomTable({ data, dataColumns, id }) {
  return (
    <Table autoHeight data={data} id={id}>
      {dataColumns.map(({ dataKey, title, width }) => (
        <Table.Column resizable width={width} key={dataKey}>
          <Table.HeaderCell>{title}</Table.HeaderCell>
          <Table.Cell dataKey={dataKey}>
            {(rowData) => get(rowData, dataKey)}
          </Table.Cell>
        </Table.Column>
      ))}
    </Table>
  );
}
```

⚠️ I'm using [lodash.get](https://docs-lodash.com/v4/get/) to work around the [nested table properties issue](https://github.com/rsuite/rsuite-table/issues/158)

