You can absolutely have middleware for subfolders.
Consider the following basic example:

`pages/_middleware.js`:
```js
import { NextResponse } from "next/server";

export default async function middleware(req, event) {
  console.log("main middleware");

  return NextResponse.next();
}
```

`pages/test/_middleware.js`:
```js
import { NextResponse } from "next/server";

export default async function middleware(req, event) {
  console.log("test submiddleware");

  return NextResponse.next();
}
```

When accessing `http://localhost:3000/test`, you will see:
```
main middleware
test submiddleware
```

**What might be happening in your case is that you are returning a Response or redirecting somewhere else, thus bypassing all subsequent middlewares.**

--------------

If I modify `pages/_middleware.js` by replacing `return NextResponse.next()` with something like `return new Response("Hello, world!")`, the `test` middleware won't be called since a Response has already been delivered.

Note that if you redirect to a page which has middlewares, they'll also be called.

Having `pages/_middleware.js` like:
```js
export default async function middleware(req, event) {
  console.log("main middleware");
  const { pathname } = req.nextUrl;

  if (pathname !== "/test") {
    return NextResponse.redirect(`/test`);
  }
}
```

will output:
```
main middleware
main middleware
test submiddleware
```

when accessing `http://localhost`

I re-wrote the split chunks logic using webpack 5's new methods. It accomplishes the same thing as the one for webpack 4 detailed in the original post : correctly find the root issuer for each imported module.

```javascript
/* eslint-disable no-restricted-syntax -- need the for loops for returning early */

/**
 * @param {RegExp[]} reasons
 * @param {string} string
 */
function matchReasonsInString(reasons, string) {
	return reasons.some((reason) => reason.test(string))
}

function getRootIssuer(module, moduleGraph) {
	const issuer = moduleGraph.getIssuer(module)
	if (issuer) {
		return getRootIssuer(issuer, moduleGraph)
	}
	return module
}

/**
 * @param {Object} config
 * @param {string[]} reasons
 */
function customSplitChunksCacheGroups(config, reasons) {
	if (config?.optimization?.splitChunks?.cacheGroups) {
		const regexReasons = reasons.map((reason) => new RegExp(`${encodeURIComponent(reason)}(.js|.jsx|.ts|.tsx)?!?$`))

		config.optimization.splitChunks.cacheGroups.commons = {
			name: 'commons',
			chunks: 'initial',
			minChunks: 1,
			priority: 20,
			test: (module, {moduleGraph}) => {
				const issuer = getRootIssuer(module, moduleGraph)
				return issuer.rawRequest && matchReasonsInString(regexReasons, issuer.rawRequest)
			},
			reuseExistingChunk: true,
		}
	}
}

module.exports = {
	default: customSplitChunksCacheGroups,
}
```

When called with `reasons = ['pages/_app', 'pages/index']`, it gives 100% correct chunking for a single page Next app. The logic for multi-page might be somewhere close to this as well.

