For anyone having the same problem, I think I figured it out. The key is not to use `getServerSideProps`, but rather, use `getInitialProps` in `pages/_app.tsx`.

```ts
import http from 'http';
import App, { AppContext, AppProps } from 'next/app';

function AppWrapper({ Component, pageProps }: AppProps) {
  return <Component {...pageProps} />;
}

// A regular expression used for matching a www domain
const wwwRegex = /^www\./;

function redirectWwwToNonWww(req: http.IncomingMessage, res: http.ServerResponse) {
  if (wwwRegex.test(String(req.headers.host))) {
    const newHost = String(req.headers.host).replace(wwwRegex, '');
    res.writeHead(301, { location: `http://${newHost}` });
    res.end();
  }
}

// Run server-side code on each request
AppWrapper.getInitialProps = async (appContext: AppContext) => {
  redirectWwwToNonWww(appContext.ctx.req, appContext.ctx.res);
  const appProps = await App.getInitialProps(appContext);
  return { ...appProps };
};

export default AppWrapper;
```

There _is_ one caveat mentioned by the docs on Custom App:

> This disables the ability to perform automatic static optimization, causing every page in your app to be server-side rendered.

But this makes sense, because each page needs to hit the redirect code before loading. Anyway, I hope this helps someone!

**Update:** It seems that adding `getInitialProps` to `_app.tsx` completely breaks NextJS's [Font Optimization](https://nextjs.org/docs/basic-features/font-optimization), so if you are using Google Fonts, using `getInitialProps` will prevent your custom fonts from loading.

Just an update for anyone searching about this: I found a better solution that allows for the preservation of static pages and Font Optimization while still enabling the redirect behavior:

It took some fiddling, but you can create a `_middleware.tsx` file within the `pages/` directory with the following code:

```tsx
import { NextRequest, NextResponse } from 'next/server';

export function middleware(req: NextRequest) {
  const host = req.headers.get('host');
  const wwwRegex = /^www\./;
  // This redirect will only take effect on a production website (on a non-localhost domain)
  if (wwwRegex.test(host) && !req.headers.get('host').includes('localhost')) {
    const newHost = host.replace(wwwRegex, '');
    return NextResponse.redirect(`https://${newHost}${req.nextUrl.pathname}`, 301);
  }
  return NextResponse.next();
}
```

[Link to Documentation on NextJS Middleware](https://nextjs.org/docs/middleware)

