For people that are still struggling with this issue. We had nextjs behind a nginx proxy server. (**jwilder**). We needed to check if **x-forwarded-proto** was set.
 >Also we needed to put middleware.ts in src/middleware.ts, not in src/pages/middleware.ts.

```ts
import { NextRequest, NextResponse } from "next/server";

export function middleware(req: NextRequest) {
    const host = req.headers.get("host");
    if (host?.slice(0, 4) === "www.") {
        return NextResponse.redirect(
            (req.headers.get("x-forwarded-proto") || req.nextUrl.protocol.slice(0,-1)) +
                "://" +
                host.slice(4) +
                req.nextUrl.pathname,
            301
        );
    }
    return NextResponse.next();
}
```

